// // This module compares two 4-bit numbers and outputs whether they are equal, greater, or less. However, it actually performs the opposite of what it claims.
module four_bit_comparator(
  input [3:0] A,
  input [3:0] B,
  output EQ,
  output GT,
  output LT
);

  assign EQ = (A == B);
  assign GT = (A > B);
  assign LT = (A < B);

endmodule
